UPDATE account_tbl
SET balance = balance - #{amount,jdbcType=DECIMAL}
WHERE account_number = #{accountNumber}
  AND customer_id = #{customerId}
  AND balance >= #{amount,jdbcType=DECIMAL}

UPDATE account_tbl
SET balance = balance + #{amount,jdbcType=DECIMAL}
WHERE account_number = #{accountNumber}
  AND customer_id = #{customerId}

